package uk.gov.moj.cpp.pcfdlrm.command.api.accesscontrol;import static org.mockito.Mockito.verify;import static org.mockito.Mockito.when;import uk.gov.moj.cpp.accesscontrol.common.providers.UserAndGroupProvider;import uk.gov.moj.cpp.accesscontrol.drools.Action;import uk.gov.moj.cpp.accesscontrol.test.utils.BaseDroolsAccessControlTest;import java.util.Map;import com.google.common.collect.ImmutableMap;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.kie.api.runtime.ExecutionResults;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;@ExtendWith(MockitoExtension.class)class ReceiveMigratedCaseRuleTest extends BaseDroolsAccessControlTest {    @Mock    private UserAndGroupProvider userAndGroupProvider;    private static final String RECEIVE_MIGRATED_CASE = "pcfdlrm.receive-migrated-case-file";    public ReceiveMigratedCaseRuleTest() {        super("COMMAND_API_SESSION");    }    @Test    void shouldAllowAuthorisedUserToReceiveMigratedCase() {        final Action action = createActionFor(RECEIVE_MIGRATED_CASE);        when(userAndGroupProvider.isSystemUser(action)).thenReturn(true);        ExecutionResults executionResults = executeRulesWith(action);        verify(userAndGroupProvider).isSystemUser(action);        assertSuccessfulOutcome(executionResults);    }    @Test    void shouldNotAllowedUnAuthorisedUserToReceiveMigratedCase() {        final Action action = createActionFor(RECEIVE_MIGRATED_CASE);        when(userAndGroupProvider.isSystemUser(action)).thenReturn(false);        ExecutionResults executionResults = executeRulesWith(action);        verify(userAndGroupProvider).isSystemUser(action);        assertFailureOutcome(executionResults);    }    @Override    protected Map<Class<?>, Object> getProviderMocks() {        return ImmutableMap.<Class<?>, Object>builder().put(UserAndGroupProvider.class, userAndGroupProvider).build();    }}